/**
 * Todo list focus management and empty state -- progressive enhancement for HTMX.
 *
 * Focus management:
 * After an HTMX delete swap removes a todo item from the DOM, focus
 * would otherwise be lost (sent to <body>). This script moves focus
 * to the logical next element:
 *   1. Next sibling todo item (if one exists)
 *   2. Previous sibling todo item (if deleted was last in list)
 *   3. The "New todo" input (if the list is now empty)
 *
 * Inline edit focus:
 * Entering edit mode focuses the edit input. Saving or canceling
 * focuses the edit link on the restored item.
 *
 * Empty state transitions:
 * When the last item is deleted, shows the "No todos yet." message
 * and hides the empty list. When the first item is added to an empty
 * list, hides the message and shows the list.
 *
 * A11y: Focus management after DOM removal is required by WCAG 2.4.3
 * (Focus Order) and is part of our HTMX Focus Management Protocol.
 */
(function () {
  "use strict";

  // Track the focus target before the swap removes the element
  var pendingFocusTarget = null;
  var pendingDeleteSwap = false;

  document.body.addEventListener("htmx:beforeSwap", function (e) {
    var target = e.detail.target;

    // Only handle swaps targeting todo items
    if (!target || !target.classList || !target.classList.contains("todo-item")) {
      return;
    }

    var responseText = e.detail.xhr ? e.detail.xhr.responseText : "";

    // Empty response = delete operation
    if (responseText.trim() === "") {
      pendingDeleteSwap = true;

      var nextItem = target.nextElementSibling;
      var prevItem = target.previousElementSibling;

      if (nextItem && nextItem.classList.contains("todo-item")) {
        pendingFocusTarget = { type: "element", el: nextItem };
      } else if (prevItem && prevItem.classList.contains("todo-item")) {
        pendingFocusTarget = { type: "element", el: prevItem };
      } else {
        pendingFocusTarget = { type: "element", el: document.getElementById("title") };
      }
      return;
    }

    // Check if the response contains the edit form (entering edit mode)
    if (responseText.indexOf("todo-item--editing") !== -1) {
      pendingFocusTarget = { type: "selector", selector: "#" + target.id + " .todo-item__edit-input" };
      return;
    }

    // Check if the response is a normal todo item (exiting edit mode)
    if (responseText.indexOf("todo-item__edit") !== -1 && responseText.indexOf("todo-item--editing") === -1) {
      pendingFocusTarget = { type: "selector", selector: "#" + target.id + " .todo-item__edit" };
      return;
    }
  });

  document.body.addEventListener("htmx:afterSettle", function () {
    // Handle empty state visibility after delete
    if (pendingDeleteSwap) {
      pendingDeleteSwap = false;
      updateEmptyState();
    }

    if (!pendingFocusTarget) {
      return;
    }

    var pending = pendingFocusTarget;
    pendingFocusTarget = null;

    var el;
    if (pending.type === "element") {
      el = pending.el;
    } else if (pending.type === "selector") {
      el = document.querySelector(pending.selector);
    }

    if (!el) {
      return;
    }

    // Make the target focusable if it isn't already
    if (!el.hasAttribute("tabindex") && el.tagName !== "INPUT" && el.tagName !== "BUTTON" && el.tagName !== "A") {
      el.setAttribute("tabindex", "-1");
    }

    el.focus();
  });

  // After adding a todo, hide empty state and show the list
  document.body.addEventListener("htmx:afterRequest", function (e) {
    var elt = e.detail.elt;
    // Only handle the add-todo form's successful POST
    if (!elt || !elt.classList || !elt.classList.contains("todo-add")) {
      return;
    }
    if (!e.detail.successful) {
      return;
    }
    updateEmptyState();
  });

  function updateEmptyState() {
    var todoList = document.querySelector(".todo-list");
    var emptyMsg = document.getElementById("todo-empty");
    if (!todoList || !emptyMsg) {
      return;
    }

    var hasItems = todoList.querySelector(".todo-item") !== null;

    if (hasItems) {
      todoList.removeAttribute("hidden");
      emptyMsg.setAttribute("hidden", "");
    } else {
      todoList.setAttribute("hidden", "");
      emptyMsg.removeAttribute("hidden");
    }
  }
})();

use sqlx::PgPool;

use crate::domain::{ContextId, NextAction, NextActionId, TodoTitle, TodoTitleError, UserId};
use crate::infrastructure::next_action_repository;

#[derive(Debug, thiserror::Error)]
pub enum AddNextActionError {
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "add_next_action",
    skip(pool, title),
    fields(user_id = %user_id.as_uuid(), context_id = %context_id.as_uuid())
)]
pub async fn add_next_action(
    pool: &PgPool,
    user_id: UserId,
    context_id: ContextId,
    title: String,
) -> Result<NextAction, AddNextActionError> {
    let title = TodoTitle::parse(title)?;
    let action = NextAction::new(user_id, context_id, title);

    next_action_repository::insert_next_action(pool, &action)
        .await
        .map_err(|e| {
            AddNextActionError::Unexpected(anyhow::anyhow!("Failed to insert next action: {e}"))
        })?;

    tracing::info!("Next action added");
    Ok(action)
}

#[tracing::instrument(
    name = "list_active_next_actions",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn list_active_next_actions(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<NextAction>, anyhow::Error> {
    let actions = next_action_repository::find_active_next_actions_by_user(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to fetch next actions: {e}"))?;

    Ok(actions)
}

#[tracing::instrument(
    name = "list_active_next_actions_by_context",
    skip(pool),
    fields(user_id = %user_id.as_uuid(), context_id = %context_id.as_uuid())
)]
pub async fn list_active_next_actions_by_context(
    pool: &PgPool,
    user_id: &UserId,
    context_id: &ContextId,
) -> Result<Vec<NextAction>, anyhow::Error> {
    let actions = next_action_repository::find_active_next_actions_by_user_and_context(
        pool, user_id, context_id,
    )
    .await
    .map_err(|e| anyhow::anyhow!("Failed to fetch next actions by context: {e}"))?;

    Ok(actions)
}

#[tracing::instrument(
    name = "count_active_next_actions",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn count_active_next_actions(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<i64, anyhow::Error> {
    let count = next_action_repository::count_active_next_actions(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to count next actions: {e}"))?;

    Ok(count)
}

#[derive(Debug, thiserror::Error)]
pub enum CompleteNextActionError {
    #[error("Next action not found")]
    NotFound,
    #[error("Not authorized to complete this next action")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "complete_next_action",
    skip(pool),
    fields(action_id = %action_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn complete_next_action(
    pool: &PgPool,
    action_id: &NextActionId,
    user_id: &UserId,
) -> Result<(), CompleteNextActionError> {
    let action = next_action_repository::find_next_action_by_id(pool, action_id)
        .await
        .map_err(|e| CompleteNextActionError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(CompleteNextActionError::NotFound)?;

    if action.user_id() != user_id {
        return Err(CompleteNextActionError::Unauthorized);
    }

    let completed = action.complete();
    if let NextAction::Completed { completed_at, .. } = &completed {
        next_action_repository::complete_next_action(pool, action_id, completed_at)
            .await
            .map_err(|e| {
                CompleteNextActionError::Unexpected(anyhow::anyhow!(
                    "Failed to complete next action: {e}"
                ))
            })?;
    }

    tracing::info!("Next action completed");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum DeleteNextActionError {
    #[error("Next action not found")]
    NotFound,
    #[error("Not authorized to delete this next action")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "delete_next_action",
    skip(pool),
    fields(action_id = %action_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn delete_next_action(
    pool: &PgPool,
    action_id: &NextActionId,
    user_id: &UserId,
) -> Result<(), DeleteNextActionError> {
    let action = next_action_repository::find_next_action_by_id(pool, action_id)
        .await
        .map_err(|e| DeleteNextActionError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(DeleteNextActionError::NotFound)?;

    if action.user_id() != user_id {
        return Err(DeleteNextActionError::Unauthorized);
    }

    next_action_repository::delete_next_action(pool, action_id)
        .await
        .map_err(|e| {
            DeleteNextActionError::Unexpected(anyhow::anyhow!("Failed to delete next action: {e}"))
        })?;

    tracing::info!("Next action deleted");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum UpdateNextActionTitleError {
    #[error("Next action not found")]
    NotFound,
    #[error("Not authorized to edit this next action")]
    Unauthorized,
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "update_next_action_title",
    skip(pool, new_title),
    fields(action_id = %action_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn update_next_action_title(
    pool: &PgPool,
    action_id: &NextActionId,
    user_id: &UserId,
    new_title: String,
) -> Result<(), UpdateNextActionTitleError> {
    let action = next_action_repository::find_next_action_by_id(pool, action_id)
        .await
        .map_err(|e| {
            UpdateNextActionTitleError::Unexpected(anyhow::anyhow!("Database error: {e}"))
        })?
        .ok_or(UpdateNextActionTitleError::NotFound)?;

    if action.user_id() != user_id {
        return Err(UpdateNextActionTitleError::Unauthorized);
    }

    let title = TodoTitle::parse(new_title)?;

    next_action_repository::update_next_action_title(pool, action_id, &title)
        .await
        .map_err(|e| {
            UpdateNextActionTitleError::Unexpected(anyhow::anyhow!(
                "Failed to update next action title: {e}"
            ))
        })?;

    tracing::info!("Next action title updated");
    Ok(())
}

